"use client";

import { useState, useRef, useEffect } from "react";
import { Send, Paperclip, Search, Users, MessageSquare, Shield, ArrowRight, Circle } from "lucide-react";

type ConversationType = "support" | "profession";

interface Message {
  id: string;
  sender: string;
  senderRole: string;
  content: string;
  time: string;
  isMe: boolean;
}

interface Conversation {
  id: string;
  type: ConversationType;
  title: string;
  subtitle: string;
  lastMessage: string;
  lastTime: string;
  unread: number;
  online: boolean;
  messages: Message[];
}

const mockConversations: Conversation[] = [
  {
    id: "1", type: "support", title: "الدعم الفني", subtitle: "تواصل مع إدارة المنصة",
    lastMessage: "تم حل المشكلة، شكراً لكم", lastTime: "منذ ساعة", unread: 2, online: true,
    messages: [
      { id: "1", sender: "الدعم الفني", senderRole: "admin", content: "مرحباً، كيف يمكننا مساعدتك؟", time: "10:00", isMe: false },
      { id: "2", sender: "أنا", senderRole: "avocat", content: "عندي مشكلة في رفع الوثائق", time: "10:05", isMe: true },
      { id: "3", sender: "الدعم الفني", senderRole: "admin", content: "نعتذر عن الإزعاج. ما نوع الخطأ الذي يظهر لك؟", time: "10:10", isMe: false },
      { id: "4", sender: "أنا", senderRole: "avocat", content: "يظهر خطأ في حجم الملف رغم أنه أقل من 10MB", time: "10:15", isMe: true },
      { id: "5", sender: "الدعم الفني", senderRole: "admin", content: "تم حل المشكلة، شكراً لكم", time: "10:30", isMe: false },
    ],
  },
  {
    id: "2", type: "profession", title: "غرفة محاميي الجزائر", subtitle: "محامو محكمة الجزائر",
    lastMessage: "هل أحد عنده خبرة في قضايا العقار؟", lastTime: "منذ 3 ساعات", unread: 5, online: false,
    messages: [
      { id: "1", sender: "الأستاذ كريم", senderRole: "avocat", content: "السلام عليكم زملائي", time: "08:00", isMe: false },
      { id: "2", sender: "الأستاذة سارة", senderRole: "avocat", content: "وعليكم السلام ورحمة الله", time: "08:05", isMe: false },
      { id: "3", sender: "أنا", senderRole: "avocat", content: "صباح الخير", time: "08:10", isMe: true },
      { id: "4", sender: "الأستاذ كريم", senderRole: "avocat", content: "هل أحد عنده خبرة في قضايا العقار؟", time: "09:00", isMe: false },
    ],
  },
  {
    id: "3", type: "profession", title: "غرفة محاميي وهران", subtitle: "محامو محكمة وهران",
    lastMessage: "جلسة غداً في القضية رقم 2026/045", lastTime: "أمس", unread: 0, online: false,
    messages: [
      { id: "1", sender: "الأستاذ ياسين", senderRole: "avocat", content: "جلسة غداً في القضية رقم 2026/045", time: "16:00", isMe: false },
    ],
  },
];

export default function MessageriePage() {
  const [conversations] = useState(mockConversations);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [message, setMessage] = useState("");
  const [msgs, setMsgs] = useState<Message[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const activeConv = conversations.find((c) => c.id === activeId);

  useEffect(() => {
    if (activeConv) setMsgs(activeConv.messages);
  }, [activeId]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [msgs]);

  const sendMessage = () => {
    if (!message.trim()) return;
    const newMsg: Message = { id: Date.now().toString(), sender: "أنا", senderRole: "me", content: message, time: new Date().toLocaleTimeString("ar-DZ", { hour: "2-digit", minute: "2-digit" }), isMe: true };
    setMsgs((prev) => [...prev, newMsg]);
    setMessage("");
  };

  if (activeConv && window.innerWidth < 768) {
    return (
      <div className="flex flex-col h-[calc(100vh-8rem)]">
        <div className="flex items-center gap-3 p-4 bg-surface border-b border-border">
          <button onClick={() => setActiveId(null)} className="p-2 rounded-lg hover:bg-gray-100"><ArrowRight className="w-5 h-5" /></button>
          <div className="w-10 h-10 bg-primary rounded-full flex items-center justify-center text-white text-sm font-bold">{activeConv.title.charAt(0)}</div>
          <div><p className="font-medium">{activeConv.title}</p><p className="text-xs text-text-light">{activeConv.subtitle}</p></div>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
          {msgs.map((msg) => (
            <div key={msg.id} className={`flex ${msg.isMe ? "justify-start" : "justify-end"}`}>
              <div className={`max-w-[80%] rounded-2xl px-4 py-2 ${msg.isMe ? "bg-primary text-white rounded-bl-sm" : "bg-surface border border-border rounded-br-sm"}`}>
                {!msg.isMe && <p className="text-xs font-semibold text-primary mb-1">{msg.sender}</p>}
                <p className="text-sm">{msg.content}</p>
                <p className={`text-xs mt-1 ${msg.isMe ? "text-white/70" : "text-text-light"}`}>{msg.time}</p>
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>
        <div className="p-4 bg-surface border-t border-border">
          <div className="flex items-center gap-2">
            <input className="input-field flex-1" placeholder="اكتب رسالتك..." value={message} onChange={(e) => setMessage(e.target.value)} onKeyDown={(e) => e.key === "Enter" && sendMessage()} />
            <button onClick={sendMessage} className="btn-primary p-2.5"><Send className="w-5 h-5" /></button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div><h1 className="text-2xl font-bold text-primary">المراسلات</h1><p className="text-text-light text-sm">تواصل مع الدعم وزملائك</p></div>
      <div className="card p-0 overflow-hidden flex h-[calc(100vh-14rem)]">
        {/* Conversation List */}
        <div className="w-80 border-l border-border flex flex-col">
          <div className="p-4 border-b border-border">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light" />
              <input className="input-field pr-9 text-sm py-2" placeholder="بحث..." />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto">
            {conversations.map((conv) => (
              <button key={conv.id} onClick={() => setActiveId(conv.id)} className={`w-full text-right p-4 border-b border-border hover:bg-gray-50 transition-colors ${activeId === conv.id ? "bg-primary/5 border-r-2 border-r-primary" : ""}`}>
                <div className="flex items-center gap-3">
                  <div className="relative">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-bold ${conv.type === "support" ? "bg-secondary" : "bg-primary"}`}>
                      {conv.type === "support" ? <Shield className="w-5 h-5" /> : <Users className="w-5 h-5" />}
                    </div>
                    {conv.online && <Circle className="absolute -bottom-0.5 -left-0.5 w-3 h-3 fill-green-500 text-green-500" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between">
                      <p className="font-medium text-sm truncate">{conv.title}</p>
                      <span className="text-xs text-text-light">{conv.lastTime}</span>
                    </div>
                    <p className="text-xs text-text-light truncate">{conv.lastMessage}</p>
                  </div>
                  {conv.unread > 0 && <span className="bg-primary text-white text-xs rounded-full w-5 h-5 flex items-center justify-center">{conv.unread}</span>}
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 flex flex-col">
          {!activeConv ? (
            <div className="flex-1 flex items-center justify-center text-text-light">
              <div className="text-center">
                <MessageSquare className="w-16 h-16 mx-auto mb-4 text-gray-300" />
                <p className="text-lg">اختر محادثة للبدء</p>
              </div>
            </div>
          ) : (
            <>
              <div className="p-4 border-b border-border flex items-center gap-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${activeConv.type === "support" ? "bg-secondary" : "bg-primary"}`}>
                  {activeConv.type === "support" ? <Shield className="w-5 h-5" /> : <Users className="w-5 h-5" />}
                </div>
                <div><p className="font-medium">{activeConv.title}</p><p className="text-xs text-text-light">{activeConv.subtitle}</p></div>
              </div>
              <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
                {msgs.map((msg) => (
                  <div key={msg.id} className={`flex ${msg.isMe ? "justify-start" : "justify-end"}`}>
                    <div className={`max-w-[70%] rounded-2xl px-4 py-2.5 ${msg.isMe ? "bg-primary text-white rounded-bl-sm" : "bg-surface border border-border rounded-br-sm"}`}>
                      {!msg.isMe && <p className="text-xs font-semibold text-primary mb-1">{msg.sender}</p>}
                      <p className="text-sm">{msg.content}</p>
                      <p className={`text-xs mt-1 ${msg.isMe ? "text-white/70" : "text-text-light"}`}>{msg.time}</p>
                    </div>
                  </div>
                ))}
                <div ref={messagesEndRef} />
              </div>
              <div className="p-4 border-t border-border">
                <div className="flex items-center gap-2">
                  <button className="p-2.5 rounded-lg hover:bg-gray-100 text-text-light"><Paperclip className="w-5 h-5" /></button>
                  <input className="input-field flex-1" placeholder="اكتب رسالتك..." value={message} onChange={(e) => setMessage(e.target.value)} onKeyDown={(e) => e.key === "Enter" && sendMessage()} />
                  <button onClick={sendMessage} className="btn-primary p-2.5"><Send className="w-5 h-5" /></button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
